var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이걸 이렇게 해서...... 여기에 꽂으면......","JPN":"これをこうして……ここに刺したら……","ENG":"So if I take this... and plug it here...","TWN":"把這個這樣……只要插在這裡的話……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"앗 뜨거! 젠장!","JPN":"熱っ！　ったく！","ENG":"Ah, that’s hot! Damn it!","TWN":"啊好燙！該死！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_ELECTRIC_BIG"},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그래도 이제 거의 다 된 것 같은데......","JPN":"でも、これでほぼ終わったはずだ……","ENG":"Still, I think I’m almost done here...","TWN":"不過所有的事情都做了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"메이슨이다. 이쪽은 대충 끝나간다.","JPN":"メイソンだ。こっちはもうすぐ完了する。","ENG":"This is Mason. I’m almost finished.","TWN":"我是梅森，這邊差不多結束了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그쪽은 좀 어때? 살아있나?","JPN":"そっちはどうだ？　生きてるか？","ENG":"How's everything over there? Is everyone alive?","TWN":"那邊怎麼樣？人還活著嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"오, 메이슨 씨. 건강한 목소리를 들으니 반갑네요.","JPN":"おお、メイソンさん。元気な声を聞けてなによりです。","ENG":"Hello, Mr. Mason. I’m happy to hear you're alive and well.","TWN":"喔，梅森先生。很高興聽到你的聲音這麼有精神。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런 젠장......","JPN":"クソ……","ENG":"Damn it...","TWN":"天殺的……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"왜 네가 이 무전기로 대답하는 거지?","JPN":"なぜあんたがその無線機でしゃべってるんだ？","ENG":"Why are you answering this radio call?","TWN":"為什麼是你用這個對講機在回答？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"다른 사람들은 설마.......","JPN":"他の人たちはまさか……","ENG":"Did the others....","TWN":"其他人難道……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"하하하. 너무 걱정 마세요.","JPN":"ははは。そんなに心配しなくてもいいですよ。","ENG":"Hahaha... Don't worry.","TWN":"哈哈哈，不要太擔心。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"다들 바퀴벌레 같아서 도망치는 거 하나는 기가 막히잖아요?","JPN":"みんな、ゴキブリみたいに逃げ足の速さだけは抜群でしょう？","ENG":"Your friends sure know how to run and hide like cockroaches.","TWN":"大家都像蟑螂一樣逃跑了，真是太厲害了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"이래서 제가 용병들을 싫어한다니까요.","JPN":"これだから私は傭兵たちが嫌いなんです。","ENG":"This is why I despise mercenaries.","TWN":"所以我才討厭傭兵。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"약해 빠진 것들이 잔머리만 늘어서 정말...... 귀찮고 짜증난달까?","JPN":"弱いくせに悪知恵ばかり働かせるから、\\nまったく……面倒でイラつくというか。","ENG":"Just a bunch of sneaky weaklings... Pesky, annoying little things.","TWN":"弱小又只會耍小聰明……真是煩到不行。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......부정할 수가 없군.","JPN":"……それは否定できないな。","ENG":"I guess I can’t deny that.","TWN":"……我無法否認呢。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"용병 놈들이 생명력 하나는 질긴 편이지.","JPN":"傭兵の生命力の強さは認めるしかない。","ENG":"Mercenaries are nothing if not resilient.","TWN":"傭兵們的生命力通常都是非常強的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그런데 왜 그런 걸 나한테 말하는데?","JPN":"ところで、どうしてそんなことを俺に言うんだ？","ENG":"Why are you talking to me about this anyway?","TWN":"但你為什麼要跟我說這些？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"당연히 시간 끌기죠. 무선 발신지를 역추적 중이거든요.","JPN":"もちろん時間稼ぎですよ。無線の発信地を逆探知してるんです。","ENG":"To buy time, of course. We're tracking the source of your transmission.","TWN":"當然是在拖時間了，因為我正在逆向追蹤你的無線電發信地點。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"RIFLE_SO_NULL_SPECIAL","text":{"KOREA":"위치 추적 완료! 남쪽 하부 B-7A 구역! 엔진실 근처입니다!","JPN":"位置追跡完了！　南側下部のBー7A区域！　エンジン室の近くです！","ENG":"We've got a location! Sector B-7A towards the southern end! It’s near the engine room!","TWN":"位置追蹤完成！南下方B-7A區域！在引擎室附近！"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_SO_NULL_SPECIAL","face":"UNIT_IDLE"},"R":{"char_id":"RIFLE_SO_NULL_SPECIAL_A","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭣? 어느새!","JPN":"何？　いつの間に！","ENG":"What? Already?!","TWN":"什麼？是什麼時候？"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"아, 수고했어요. 여러분.","JPN":"あ、お疲れ様でした。皆さん。","ENG":"Ah, good work, everyone.","TWN":"好，辛苦了，各位。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"그럼 남은 이야기는 직접 만나서 하도록 하죠.","JPN":"それじゃあ、あとの話は直接会ってからにしましょう。","ENG":"I guess we can continue our conversation in person.","TWN":"那麼剩下的事情就見面再說吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"혹시나 해서 말씀드리는데, 괜히 쓸데없는 짓 하다가 어디 부러지지 마시고 착하게 숨만 쉬고 계시다가 항복하길 추천합니다.","JPN":"念のために言っておきますが、\\n余計なことして骨折り損になる前に、\\n大人しく降伏することをおすすめします。","ENG":"If I may, I’d like to advise you to surrender quietly instead of getting yourself hurt for no reason.","TWN":"以防萬一所以再次提醒你，無謂的抵抗只會讓你受傷，我建議你乖乖在那邊休息，然後投降吧。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"제가 걷는 걸 참 싫어하는데 거기까지 걸어가면 아마 짜증이 많이 나 있는 상태일 것 같거든요.","JPN":"私は歩くのが嫌いなので、そこまで歩いていったらかなりイライラしていると思うんですね。","ENG":"I really hate walking, you see. So I may be rather irritated by the time I get there.","TWN":"我很討厭走路，要是一路走到那裡，我的心情可能會不太好。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JAKE_DELTA_PLAIN_NULL","text":{"KOREA":"다 메이슨 씨를 위한 충고라고 생각해 주세요. 그럼 이만.","JPN":"これも全部メイソンさんのための忠告だと思ってください。ではこれで。","ENG":"Just a little friendly advice for you, Mr. Mason. Bye now.","TWN":"請把這些話當作是給梅森先生的忠告，那就掰啦。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_PLAIN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};